addEventListener("fetch", event => {
  const url = new URL(event.request.url);
  const ttl = parseInt(url.searchParams.get("ttl"));
  const cacheKey = url.searchParams.get("cache_key");

  if (isNaN(ttl) || !cacheKey) {
    event.respondWith(fetchAndCache(event));
  } else {
    event.respondWith(cachedResponse(event, ttl, cacheKey));
  }
});

async function fetchAndCache(event) {
  const response = await fetch(event.request);
  const cache = caches.default;
  const cacheKey = getCacheKey(event.request);
  await cache.put(cacheKey, response.clone());
  return response;
}

async function cachedResponse(event, ttl, cacheKey) {
  const cache = caches.default;
  const response = await cache.match(cacheKey);
  if (response) {
    return response;
  } else {
    const freshResponse = await fetchAndCache(event);
    return freshResponse;
  }
}

function getCacheKey(request) {
  // Generate a unique cache key based on the request URL and headers
  const url = new URL(request.url);
  const headers = {};
  for (const [key, value] of request.headers.entries()) {
    headers[key.toLowerCase()] = value;
  }
  return `${url.href}-${JSON.stringify(headers)}`;
}